using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");
        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_Null_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");
        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");
        StringAssert.Contains(result, "Dr.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post! #1");
        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("---Hello");
        StringAssert.StartsWith(result, "h");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithTrailingSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello!!!");
        StringAssert.EndsWith(result, "o");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_Whitespace_Throws()
    {
        _formatter.GenerateSlug("  ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarFormat()
    {
        var result = _formatter.FormatCurrency(9.99m);
        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_Result_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_Result_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(5m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-42.50m);
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_Result_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");
        StringAssert.Matches(result, new Regex(@"^£-?\d+\.\d{2}$"));
    }
}

